/* =========================================================
    💰 ACCOUNTANT & FINANCE (САНХҮҮ)
   ========================================================= */

// 1. Урсгал зардал бүртгэх
app.post("/api/finance/add-expense", authenticate, async (req, res) => {
  try {
    const { center_id, description, amount, category } = req.body;
    // Хамгийн сүүлийн READY төлөвтэй тайланг олох
    const [activeReport] = await db.query(
      "SELECT id FROM reports WHERE center_id = ? AND status = 'READY' ORDER BY generated_at DESC LIMIT 1",
      [center_id]
    );
    const reportId = activeReport.length > 0 ? activeReport[0].id : null;

    await db.query(
      "INSERT INTO expenses (center_id, description, amount, category, report_id) VALUES (?, ?, ?, ?, ?)",
      [center_id, description, amount, category, reportId]
    );
    res.json({ success: true, message: "Зардал амжилттай бүртгэгдлээ" });
  } catch (err) {
    res.status(500).json({ error: "Зардал бүртгэхэд алдаа гарлаа" });
  }
});

// 2. Санхүүгийн тайлан нэгтгэж гаргах (Daily/Weekly/Monthly)
app.post("/api/finance/generate-report", authenticate, async (req, res) => {
  const { center_id, report_type } = req.body;
  try {
    // Нийт орлого
    const [income] = await db.query(
      "SELECT SUM(total_price) as total FROM reservations WHERE status = 'PAID' AND pc_id IN (SELECT id FROM pcs WHERE center_id = ?)",
      [center_id]
    );
    // Нийт зардал
    const [expense] = await db.query(
      "SELECT SUM(amount) as total FROM expenses WHERE center_id = ?",
      [center_id]
    );

    const totalIncome = income[0].total || 0;
    const totalExpense = expense[0].total || 0;
    const netProfit = totalIncome - totalExpense;

    const [result] = await db.query(
      "INSERT INTO reports (user_id, center_id, report_type, total_income, total_expense, net_profit, status) VALUES (?, ?, ?, ?, ?, ?, 'READY')",
      [req.user.id, center_id, report_type, totalIncome, totalExpense, netProfit]
    );

    res.json({ success: true, reportId: result.insertId, netProfit });
  } catch (err) {
    res.status(500).json({ error: "Тайлан боловсруулахад алдаа гарлаа" });
  }
});

// 3. Ээлжийн тооцоо тулгах (Cash Reconciliation)
app.put("/api/finance/reconcile/:reportId", authenticate, async (req, res) => {
  const { cash_reported, online_reported } = req.body;
  const reportId = req.params.reportId;
  try {
    const [report] = await db.query("SELECT total_income FROM reports WHERE id = ?", [reportId]);
    if (!report.length) return res.status(404).json({ error: "Тайлан олдсонгүй" });

    const systemIncome = report[0].total_income;
    const discrepancy = (Number(cash_reported) + Number(online_reported)) - systemIncome;

    await db.query(
      "UPDATE reports SET cash_reported = ?, online_reported = ?, discrepancy = ?, status = 'COMPLETED' WHERE id = ?",
      [cash_reported, online_reported, discrepancy, reportId]
    );

    res.json({ success: true, discrepancy });
  } catch (err) {
    res.status(500).json({ error: "Тооцоо тулгахад алдаа гарлаа" });
  }
});

/* =========================================================
    📅 RESERVATIONS (ЗАХИАЛГА)
   ========================================================= */
app.post("/api/reservations", authenticate, async (req, res) => {
  const conn = await db.getConnection();
  try {
    const { centerId, total_price, start_time, end_time } = req.body;
    await conn.beginTransaction();

    const [wallet] = await conn.query("SELECT id, balance FROM wallets WHERE user_id = ? FOR UPDATE", [req.user.id]);
    if (!wallet.length || Number(wallet[0].balance) < total_price) throw new Error("Үлдэгдэл хүрэлцэхгүй байна");

    const [pc] = await conn.query("SELECT id FROM pcs WHERE center_id = ? AND status = 'AVAILABLE' LIMIT 1 FOR UPDATE", [centerId]);
    if (!pc.length) throw new Error("Боломжтой PC олдсонгүй");

    const pcId = pc[0].id;
    const [resResult] = await conn.query(
      "INSERT INTO reservations (user_id, pc_id, start_time, end_time, total_price, status) VALUES (?, ?, ?, ?, ?, 'PAID')",
      [req.user.id, pcId, start_time || new Date(), end_time, total_price]
    );

    await conn.query("INSERT INTO wallet_transactions (user_id, type, amount, description) VALUES (?, 'BOOKING', ?, ?)", 
      [req.user.id, -total_price, `Захиалга #${resResult.insertId}`]);

    await conn.query("UPDATE wallets SET balance = balance - ? WHERE user_id = ?", [total_price, req.user.id]);
    await conn.query("UPDATE pcs SET status = 'BOOKED' WHERE id = ?", [pcId]);

    await conn.commit();
    io.emit("status-changed", { pc_id: pcId, status: "BOOKED", centerId });
    res.json({ success: true, balance: Number(wallet[0].balance) - total_price });
  } catch (err) {
    await conn.rollback();
    res.status(400).json({ error: err.message });
  } finally {
    conn.release();
  }
});

